// v1 receiver — accepts all payloads, surfaces them in n8n's execution log.
// HMAC verification is DEFERRED: n8n's vm sandbox in the Code node does NOT
// expose 'crypto' (neither require('crypto') nor globalThis.crypto), so the
// HMAC-SHA256 verify against the ElevenLabs-Signature header can't run here.
// To upgrade: insert an n8n-nodes-base.crypto node BEFORE this one with
// type=HMAC, algorithm=SHA256, secret=<the wsec_ value from the workspace
// webhook>, value={{$json.rawBody}}, then compare its output against the
// header's v0 component in an IF node. Until that refactor, this receiver is
// open — anything POSTed here lands in execution log and is treated as valid.
const item = $input.first();
const headers = item.json.headers || {};
const sigHeader = headers['elevenlabs-signature'] || headers['ElevenLabs-Signature'] || '';
const payload = typeof item.json.body === 'string' ? JSON.parse(item.json.body) : (item.json.body || item.json);

return [{json: {
  verified: null,
  verification_note: 'HMAC deferred — accepts all',
  signature_header_present: Boolean(sigHeader),
  received_at: new Date().toISOString(),
  type: payload.type || 'unknown',
  conversation_id: payload.data?.conversation_id,
  agent_id: payload.data?.agent_id,
  payload
}}];
